import React from 'react';
import logo from './logo.svg';
import './App.css';

interface Music {
  name : string;
  artist : string;
  playcount : number;
}

interface TopTracks {
  tracks : Array<Music>;
}

const fetchTopTracks = async () : Promise <Array<Music> | string> => {
  const api = 'http://ws.audioscrobbler.com/2.0/?method=user.gettoptracks&user=gfxnx&api_key=c9d3233f3430ee28ba0e643cb973eac5&format=json'
  try {
    const response = await fetch(api); 
    if(!response.ok){
      throw new Error(`API call error : ${response.status}`)
    }
    const {data} = await response.json();
    return data;
  } catch (error : any) {
    return (`Error returning API info ${error.status}`);
  }
}

fetchTopTracks().then((data) => {
  data.toptracks.forEach((music: Music)=> {
    console.log(music); 
  });
});

